// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M, K;
        scanf("%d %d %d", &N, &M, &K);
        int x1, y1, x2, y2;
        long long area = 0;
        for (int i = 0; i < K; i++) {
            scanf("%d %d %d %d", &x1, &y1, &x2, &y2);
            // Calculate the area of the region separated by the electric fence
            long long regionArea = (x2 - x1) * (y2 - y1);
            area += regionArea;
        }
        // Calculate the expected area lost
        long long expectedArea = (N * M - area) / (K + 1);
        printf("%lld\n", expectedArea % MOD);
    }
    return 0;
}

